const msgData   = $('Extrair Mensagem').first().json
const sessionRow = $('Buscar Sessão').first()?.json

const phone        = msgData.phone
const incoming     = msgData.incomingText
const rawText      = msgData.rawText
const phoneNumberId = msgData.phoneNumberId

const currentState = sessionRow?.current_state ?? 'new'
const ctx          = typeof sessionRow?.context === 'string'
  ? JSON.parse(sessionRow.context)
  : (sessionRow?.context ?? {})

// ── Helpers ──────────────────────────────────────────────────
const isGreeting = /^(oi|olá|ola|alo|hey|hi|hello|bom dia|boa tarde|boa noite|inicio|início|start)$/i.test(incoming)
const isCancel   = /^(cancelar|cancel|sair|exit|parar|stop)$/i.test(incoming)
const isRestart  = /^(recomeçar|recomecar|restart|novo|nova simulação|nova simulacao)$/i.test(incoming)

const FINANCING_MAP = {
  '1':'imobiliario','imovel':'imobiliario','imóvel':'imobiliario','casa':'imobiliario','apartamento':'imobiliario','imobiliario':'imobiliario',
  '2':'veiculo','veiculo':'veiculo','veículo':'veiculo','carro':'veiculo','moto':'veiculo','caminhao':'veiculo',
  '3':'pessoal','pessoal':'pessoal',
  '4':'consignado','consignado':'consignado',
  '5':'empresa','empresa':'empresa','pj':'empresa',
  '6':'equipamento','equipamento':'equipamento',
  '7':'rural','rural':'rural','agricola':'rural','agrícola':'rural',
}

const CIVIL_MAP      = {'1':'single','2':'married','3':'divorced','4':'widowed','5':'stable_union'}
const PROPERTY_MAP   = {'1':'residential','2':'commercial','3':'land','4':'rural'}
const VEHICLE_MAP    = {'1':'car','2':'motorcycle','3':'truck','4':'other'}
const FUEL_MAP       = {'1':'flex','2':'gasoline','3':'diesel','4':'electric','5':'hybrid'}
const SELLER_MAP     = {'1':'dealer','2':'dealership','3':'private'}
const INTENT_MAP     = {'1':'buying','2':'researching'}
const EMPLOY_MAP     = {'1':'clt','2':'public_servant','3':'self_employed','4':'business_owner','5':'retired'}
const RE_OBJ_MAP     = {'1':'financing','2':'home_equity','3':'portability'}
const TIMELINE_MAP   = {'1':'immediate','2':'3m','3':'6m','4':'12m','5':'researching'}
const TERM_SHORTCUTS = {'1':12,'2':24,'3':36,'4':48,'5':60,'6':84,'7':120,'8':180,'9':240,'10':360}
const VALID_UF       = ['AC','AL','AP','AM','BA','CE','DF','ES','GO','MA','MT','MS','MG','PA','PB','PR','PE','PI','RJ','RN','RS','RO','RR','SC','SP','SE','TO']

function isValidCPF(cpf) {
  const c = cpf.replace(/\D/g,'')
  if (c.length!==11 || /^(\d)\1+$/.test(c)) return false
  let s=0; for(let i=0;i<9;i++) s+=+c[i]*(10-i)
  let r=(s*10)%11; if(r===10||r===11) r=0; if(r!==+c[9]) return false
  s=0; for(let i=0;i<10;i++) s+=+c[i]*(11-i)
  r=(s*10)%11; if(r===10||r===11) r=0; return r===+c[10]
}
function isValidCNPJ(cnpj) {
  const c = cnpj.replace(/\D/g,'')
  if (c.length!==14 || /^(\d)\1+$/.test(c)) return false
  let s=0; const w1=[5,4,3,2,9,8,7,6,5,4,3,2]
  for(let i=0;i<12;i++) s+=+c[i]*w1[i]
  let r=s%11; let d1=r<2?0:11-r
  if(d1!==+c[12]) return false
  s=0; const w2=[6,5,4,3,2,9,8,7,6,5,4,3,2]
  for(let i=0;i<13;i++) s+=+c[i]*w2[i]
  r=s%11; let d2=r<2?0:11-r
  return d2===+c[13]
}
function parseMoney(t) {
  return parseFloat(t.replace(/[^0-9,.]/g,'').replace(/\./g,'').replace(',','.'))
}
function fmt(v) {
  return new Intl.NumberFormat('pt-BR',{style:'currency',currency:'BRL'}).format(v)
}
function titleCase(s) {
  return s.split(' ').map(w=>w.charAt(0).toUpperCase()+w.slice(1)).join(' ')
}

let result = null

// ── Globais ──────────────────────────────────────────────────
if (isCancel && currentState !== 'new') {
  result = { response: 'Atendimento encerrado. Envie "oi" quando quiser simular novamente.', newState: 'abandoned', ctx: {} }
}
if (!result && isRestart) {
  result = {
    response: '🔄 Vamos recomeçar!\n\nPara qual finalidade você deseja simular?\n\n1️⃣ Imóvel\n2️⃣ Veículo\n3️⃣ Crédito Pessoal\n4️⃣ Consignado\n5️⃣ Empresa/PJ\n6️⃣ Equipamento\n7️⃣ Rural',
    newState: 'awaiting_financing_type', ctx: {},
  }
}

// ── Saudação ──────────────────────────────────────────────────
if (!result && (currentState === 'new' || isGreeting)) {
  const inProgress = !['new','completed','abandoned'].includes(currentState)
  if (inProgress && !isGreeting) {
    result = {
      response: `Bem-vindo de volta! 👋\n\nVocê tem uma simulação em andamento.\n\n1️⃣ Continuar\n2️⃣ Recomeçar`,
      newState: currentState, ctx,
    }
  } else {
    result = {
      response: '👋 Olá! Bem-vindo ao simulador de financiamentos!\n\nPara qual finalidade você deseja simular?\n\n1️⃣ Imóvel\n2️⃣ Veículo\n3️⃣ Crédito Pessoal\n4️⃣ Consignado\n5️⃣ Empresa/PJ\n6️⃣ Equipamento\n7️⃣ Rural',
      newState: 'awaiting_financing_type', ctx: {},
    }
  }
}

// ── Tipo de financiamento ──────────────────────────────────────
if (!result && currentState === 'awaiting_financing_type') {
  const ft = FINANCING_MAP[incoming]
  if (!ft) {
    result = { response: '❌ Opção inválida. Escolha de 1 a 7:', newState: currentState, ctx }
  } else {
    result = {
      response: `Você escolheu *${ft}* ✅\n\nVocê é pessoa física ou jurídica?\n\n1️⃣ Pessoa Física (CPF)\n2️⃣ Pessoa Jurídica (CNPJ)`,
      newState: 'awaiting_person_type', ctx: { financingType: ft },
    }
  }
}

// ── Tipo de pessoa ─────────────────────────────────────────────
if (!result && currentState === 'awaiting_person_type') {
  if (incoming === '1' || /^(pf|física|fisica|cpf)/.test(incoming)) {
    result = { response: 'Qual é o seu *nome completo*?', newState: 'awaiting_name', ctx: { ...ctx, personType: 'pf' } }
  } else if (incoming === '2' || /^(pj|jurídica|juridica|cnpj|empresa)/.test(incoming)) {
    result = { response: 'Qual o *nome da empresa*?', newState: 'awaiting_company_name', ctx: { ...ctx, personType: 'pj' } }
  } else {
    result = { response: '❌ Escolha 1 para Pessoa Física ou 2 para Pessoa Jurídica:', newState: currentState, ctx }
  }
}

// ── PJ: nome da empresa ────────────────────────────────────────
if (!result && currentState === 'awaiting_company_name') {
  if (rawText.length < 2) {
    result = { response: '❌ Informe o nome da empresa:', newState: currentState, ctx }
  } else {
    result = { response: 'Qual o *CNPJ* da empresa? (somente números)', newState: 'awaiting_cnpj', ctx: { ...ctx, companyName: rawText } }
  }
}
if (!result && currentState === 'awaiting_cnpj') {
  if (!isValidCNPJ(incoming)) {
    result = { response: '❌ CNPJ inválido. Informe os 14 dígitos:', newState: currentState, ctx }
  } else {
    result = { response: 'Qual o *nome do responsável*?', newState: 'awaiting_responsible_name', ctx: { ...ctx, cnpj: incoming.replace(/\D/g,'') } }
  }
}
if (!result && currentState === 'awaiting_responsible_name') {
  if (rawText.trim().split(/\s+/).length < 2) {
    result = { response: '❌ Informe o nome completo do responsável:', newState: currentState, ctx }
  } else {
    result = { response: 'Qual o *e-mail de contato*?', newState: 'awaiting_email', ctx: { ...ctx, responsibleName: titleCase(rawText.trim()) } }
  }
}

// ── PF: dados pessoais ─────────────────────────────────────────
if (!result && currentState === 'awaiting_name') {
  if (rawText.trim().split(/\s+/).length < 2) {
    result = { response: '❌ Informe seu nome completo (nome e sobrenome):', newState: currentState, ctx }
  } else {
    result = { response: `Obrigado, ${titleCase(rawText.trim())}! 😊\n\nQual é o seu *CPF*? (somente números)`, newState: 'awaiting_cpf', ctx: { ...ctx, name: titleCase(rawText.trim()) } }
  }
}
if (!result && currentState === 'awaiting_cpf') {
  if (!isValidCPF(incoming)) {
    result = { response: '❌ CPF inválido. Informe os 11 dígitos:', newState: currentState, ctx }
  } else {
    result = { response: 'CPF registrado ✅\n\nQual sua *data de nascimento*? (DD/MM/AAAA)', newState: 'awaiting_birth_date', ctx: { ...ctx, cpf: incoming.replace(/\D/g,'') } }
  }
}
if (!result && currentState === 'awaiting_birth_date') {
  const m = rawText.match(/^(\d{2})\/(\d{2})\/(\d{4})$/)
  if (!m) {
    result = { response: '❌ Data inválida. Use DD/MM/AAAA:', newState: currentState, ctx }
  } else {
    const age = new Date().getFullYear() - parseInt(m[3])
    if (age < 18) {
      result = { response: '❌ É necessário ter pelo menos 18 anos para simular.', newState: currentState, ctx }
    } else {
      result = { response: 'Registrado ✅\n\nQual seu *estado civil*?\n\n1️⃣ Solteiro(a)\n2️⃣ Casado(a)\n3️⃣ Divorciado(a)\n4️⃣ Viúvo(a)\n5️⃣ União Estável', newState: 'awaiting_civil_status', ctx: { ...ctx, birthDate: rawText } }
    }
  }
}
if (!result && currentState === 'awaiting_civil_status') {
  const cs = CIVIL_MAP[incoming]
  if (!cs) {
    result = { response: '❌ Escolha de 1 a 5:', newState: currentState, ctx }
  } else {
    result = { response: 'Registrado ✅\n\nQual seu *e-mail*?', newState: 'awaiting_email', ctx: { ...ctx, civilStatus: cs } }
  }
}

// ── Email e telefone (PF e PJ) ─────────────────────────────────
if (!result && currentState === 'awaiting_email') {
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(incoming)) {
    result = { response: '❌ E-mail inválido. Informe um e-mail válido:', newState: currentState, ctx }
  } else {
    result = { response: 'E-mail registrado ✅\n\nQual o *celular* (com DDD)?', newState: 'awaiting_phone', ctx: { ...ctx, email: incoming } }
  }
}
if (!result && currentState === 'awaiting_phone') {
  const digits = incoming.replace(/\D/g,'')
  if (digits.length < 10 || digits.length > 11) {
    result = { response: '❌ Celular inválido. Informe com DDD (10 ou 11 dígitos):', newState: currentState, ctx }
  } else {
    if (ctx.personType === 'pj') {
      result = { response: 'Qual o *faturamento mensal* da empresa? (ex: 50000)', newState: 'awaiting_company_revenue', ctx: { ...ctx, phone: digits } }
    } else {
      result = { response: 'Em qual *cidade* você mora?', newState: 'awaiting_city', ctx: { ...ctx, phone: digits } }
    }
  }
}

// ── PJ: faturamento ───────────────────────────────────────────
if (!result && currentState === 'awaiting_company_revenue') {
  const v = parseMoney(incoming)
  if (isNaN(v) || v <= 0) {
    result = { response: '❌ Valor inválido. Informe o faturamento mensal:', newState: currentState, ctx }
  } else {
    result = { response: `${fmt(v)} ✅\n\nQual o *valor* que precisa financiar? (ex: 200000)`, newState: 'awaiting_loan_amount', ctx: { ...ctx, companyRevenue: v } }
  }
}

// ── PF: cidade/estado/renda ────────────────────────────────────
if (!result && currentState === 'awaiting_city') {
  if (rawText.trim().length < 2) {
    result = { response: '❌ Informe o nome da cidade:', newState: currentState, ctx }
  } else {
    result = { response: `${titleCase(rawText.trim())} ✅\n\nQual o *estado* (UF)? Ex: SP, RJ, MG`, newState: 'awaiting_state', ctx: { ...ctx, city: titleCase(rawText.trim()) } }
  }
}
if (!result && currentState === 'awaiting_state') {
  const uf = incoming.toUpperCase().trim()
  if (!VALID_UF.includes(uf)) {
    result = { response: '❌ UF inválida (ex: SP, RJ, MG):', newState: currentState, ctx }
  } else {
    result = { response: `${uf} ✅\n\nQual sua *renda mensal bruta*? (ex: 5000)`, newState: 'awaiting_monthly_income', ctx: { ...ctx, state: uf } }
  }
}
if (!result && currentState === 'awaiting_monthly_income') {
  const v = parseMoney(incoming)
  if (isNaN(v) || v <= 0) {
    result = { response: '❌ Valor inválido. Informe sua renda mensal (ex: 5000):', newState: currentState, ctx }
  } else {
    result = { response: `${fmt(v)} ✅\n\nDeseja incluir a renda de um *co-participante*? (cônjuge, etc.)\n\n1️⃣ Sim\n2️⃣ Não`, newState: 'awaiting_co_participant', ctx: { ...ctx, monthlyIncome: v } }
  }
}
if (!result && currentState === 'awaiting_co_participant') {
  if (incoming === '1' || /^sim/.test(incoming)) {
    result = { response: 'Qual a *renda do co-participante*? (ex: 3000)', newState: 'awaiting_co_participant_income', ctx: { ...ctx, hasCoParticipant: true } }
  } else {
    result = { newState: 'route_to_product', ctx: { ...ctx, hasCoParticipant: false }, _routeToProduct: true }
  }
}
if (!result && currentState === 'awaiting_co_participant_income') {
  const v = parseMoney(incoming)
  if (isNaN(v) || v <= 0) {
    result = { response: '❌ Valor inválido. Informe a renda do co-participante:', newState: currentState, ctx }
  } else {
    result = { newState: 'route_to_product', ctx: { ...ctx, coParticipantIncome: v }, _routeToProduct: true }
  }
}

// ── Roteamento para o produto após dados pessoais ──────────────
if ((!result && currentState === 'route_to_product') || result?._routeToProduct) {
  const c = result ? result.ctx : ctx
  const ft = c.financingType
  let response, newState
  if (ft === 'imobiliario') {
    response = 'Qual o *objetivo* com o imóvel?\n\n1️⃣ Financiar imóvel\n2️⃣ Crédito com garantia (home equity)\n3️⃣ Portabilidade de financiamento'
    newState = 'awaiting_re_objective'
  } else if (ft === 'veiculo') {
    response = 'Qual tipo de veículo?\n\n1️⃣ Carro\n2️⃣ Moto\n3️⃣ Caminhão\n4️⃣ Outro'
    newState = 'awaiting_vehicle_type'
  } else {
    response = 'Qual o *valor* que você precisa? (ex: 20000)'
    newState = 'awaiting_loan_amount'
  }
  result = { response, newState, ctx: c }
}

// ── Imobiliário ───────────────────────────────────────────────
if (!result && currentState === 'awaiting_re_objective') {
  const obj = RE_OBJ_MAP[incoming]
  if (!obj) {
    result = { response: '❌ Escolha 1, 2 ou 3:', newState: currentState, ctx }
  } else {
    result = { response: 'Qual o momento da compra?\n\n1️⃣ Imediato\n2️⃣ Em até 3 meses\n3️⃣ Em até 6 meses\n4️⃣ Em até 12 meses\n5️⃣ Apenas pesquisando', newState: 'awaiting_purchase_timeline', ctx: { ...ctx, realEstateObjective: obj } }
  }
}
if (!result && currentState === 'awaiting_purchase_timeline') {
  const tl = TIMELINE_MAP[incoming]
  if (!tl) {
    result = { response: '❌ Escolha de 1 a 5:', newState: currentState, ctx }
  } else {
    result = { response: 'Você tem saldo de *FGTS* para usar?\n\n1️⃣ Sim\n2️⃣ Não', newState: 'awaiting_fgts', ctx: { ...ctx, purchaseTimeline: tl } }
  }
}
if (!result && currentState === 'awaiting_fgts') {
  if (incoming === '1' || /^sim/.test(incoming)) {
    result = { response: 'Qual o saldo aproximado do *FGTS*? (ex: 15000)', newState: 'awaiting_fgts_amount', ctx }
  } else {
    result = { response: 'Ok.\n\nVocê tem *entrada* além do FGTS?\n\n1️⃣ Sim\n2️⃣ Não', newState: 'awaiting_down_payment', ctx: { ...ctx, fgtsAmount: 0 } }
  }
}
if (!result && currentState === 'awaiting_fgts_amount') {
  const v = parseMoney(incoming)
  if (isNaN(v) || v <= 0) {
    result = { response: '❌ Valor inválido. Informe o saldo do FGTS:', newState: currentState, ctx }
  } else {
    result = { response: `FGTS: ${fmt(v)} ✅\n\nVocê tem *entrada adicional*?\n\n1️⃣ Sim\n2️⃣ Não`, newState: 'awaiting_down_payment', ctx: { ...ctx, fgtsAmount: v } }
  }
}
if (!result && currentState === 'awaiting_down_payment') {
  if (incoming === '1' || /^sim/.test(incoming)) {
    result = { response: 'Qual o valor da *entrada*? (ex: 30000)', newState: 'awaiting_down_payment_amount', ctx }
  } else {
    result = { response: 'Qual o *valor do imóvel*? (ex: 350000)', newState: 'awaiting_property_value', ctx: { ...ctx, downPaymentAmount: 0 } }
  }
}
if (!result && currentState === 'awaiting_down_payment_amount') {
  const v = parseMoney(incoming)
  if (isNaN(v) || v <= 0) {
    result = { response: '❌ Valor inválido:', newState: currentState, ctx }
  } else {
    result = { response: `${fmt(v)} ✅\n\nQual o *valor do imóvel*? (ex: 350000)`, newState: 'awaiting_property_value', ctx: { ...ctx, downPaymentAmount: v } }
  }
}
if (!result && currentState === 'awaiting_property_value') {
  const v = parseMoney(incoming)
  if (isNaN(v) || v <= 0) {
    result = { response: '❌ Valor inválido:', newState: currentState, ctx }
  } else {
    result = { response: `${fmt(v)} ✅\n\nQual o *tipo do imóvel*?\n\n1️⃣ Residencial\n2️⃣ Comercial\n3️⃣ Terreno\n4️⃣ Rural`, newState: 'awaiting_property_type', ctx: { ...ctx, propertyValue: v } }
  }
}
if (!result && currentState === 'awaiting_property_type') {
  const pt = PROPERTY_MAP[incoming]
  if (!pt) {
    result = { response: '❌ Escolha de 1 a 4:', newState: currentState, ctx }
  } else {
    result = { response: `${pt} ✅\n\nEm qual *cidade* fica o imóvel?`, newState: 'awaiting_property_city', ctx: { ...ctx, propertyType: pt } }
  }
}
if (!result && currentState === 'awaiting_property_city') {
  result = { response: `${titleCase(rawText.trim())} ✅\n\nQual o *estado* do imóvel? (UF)`, newState: 'awaiting_property_state', ctx: { ...ctx, propertyCity: titleCase(rawText.trim()) } }
}
if (!result && currentState === 'awaiting_property_state') {
  const uf = incoming.toUpperCase().trim()
  if (!VALID_UF.includes(uf)) {
    result = { response: '❌ UF inválida (ex: SP, RJ):', newState: currentState, ctx }
  } else {
    result = { response: `${uf} ✅\n\nO financiamento já inclui as taxas (ITBI, registro, avaliação)?\n\n1️⃣ Sim, incluir taxas\n2️⃣ Não, apenas o imóvel`, newState: 'awaiting_include_fees', ctx: { ...ctx, propertyState: uf } }
  }
}
if (!result && currentState === 'awaiting_include_fees') {
  const inc = incoming === '1' || /^sim/.test(incoming)
  const label = inc ? 'Com taxas ✅' : 'Só o imóvel ✅'
  result = { response: `${label}\n\nEm quantos *meses* quer financiar?\n\n1️⃣ 12 meses\n2️⃣ 24 meses\n3️⃣ 36 meses\n4️⃣ 48 meses\n5️⃣ 60 meses\n6️⃣ 84 meses\n7️⃣ 120 meses\n8️⃣ 180 meses\n9️⃣ 240 meses\n🔟 360 meses\n\nOu informe diretamente (6 a 420):`, newState: 'awaiting_term', ctx: { ...ctx, includeFees: inc } }
}

// ── Veículo ───────────────────────────────────────────────────
if (!result && currentState === 'awaiting_vehicle_type') {
  const vt = VEHICLE_MAP[incoming]
  if (!vt) {
    result = { response: '❌ Escolha de 1 a 4:', newState: currentState, ctx }
  } else {
    result = { response: 'Qual a *marca* do veículo? (ex: Toyota, Honda)', newState: 'awaiting_vehicle_brand', ctx: { ...ctx, vehicleType: vt } }
  }
}
if (!result && currentState === 'awaiting_vehicle_brand') {
  result = { response: `${titleCase(rawText.trim())} ✅\n\nQual o *modelo*? (ex: Corolla, Civic)`, newState: 'awaiting_vehicle_model', ctx: { ...ctx, vehicleBrand: titleCase(rawText.trim()) } }
}
if (!result && currentState === 'awaiting_vehicle_model') {
  result = { response: `${titleCase(rawText.trim())} ✅\n\nQual o *ano* do veículo?`, newState: 'awaiting_vehicle_year', ctx: { ...ctx, vehicleModel: titleCase(rawText.trim()) } }
}
if (!result && currentState === 'awaiting_vehicle_year') {
  const y = parseInt(incoming)
  if (isNaN(y) || y < 1990 || y > new Date().getFullYear() + 1) {
    result = { response: `❌ Ano inválido. Informe entre 1990 e ${new Date().getFullYear() + 1}:`, newState: currentState, ctx }
  } else {
    result = { response: `${y} ✅\n\nQual o *combustível*?\n\n1️⃣ Flex\n2️⃣ Gasolina\n3️⃣ Diesel\n4️⃣ Elétrico\n5️⃣ Híbrido`, newState: 'awaiting_vehicle_fuel', ctx: { ...ctx, vehicleYear: y } }
  }
}
if (!result && currentState === 'awaiting_vehicle_fuel') {
  const f = FUEL_MAP[incoming]
  if (!f) {
    result = { response: '❌ Escolha de 1 a 5:', newState: currentState, ctx }
  } else {
    result = { response: `${f} ✅\n\nComo você vai comprar?\n\n1️⃣ Loja / Revendedora\n2️⃣ Concessionária\n3️⃣ Direto com o dono`, newState: 'awaiting_seller_context', ctx: { ...ctx, vehicleFuel: f } }
  }
}
if (!result && currentState === 'awaiting_seller_context') {
  const sc = SELLER_MAP[incoming]
  if (!sc) {
    result = { response: '❌ Escolha de 1 a 3:', newState: currentState, ctx }
  } else {
    result = { response: `${sc} ✅\n\nVocê está comprando ou pesquisando?\n\n1️⃣ Pronto para comprar\n2️⃣ Ainda pesquisando`, newState: 'awaiting_purchase_intent', ctx: { ...ctx, sellerContext: sc } }
  }
}
if (!result && currentState === 'awaiting_purchase_intent') {
  const pi = INTENT_MAP[incoming]
  if (!pi) {
    result = { response: '❌ Escolha 1 ou 2:', newState: currentState, ctx }
  } else {
    result = { response: `✅\n\nVocê possui *CNH* válida?\n\n1️⃣ Sim\n2️⃣ Não`, newState: 'awaiting_cnh', ctx: { ...ctx, purchaseIntent: pi } }
  }
}
if (!result && currentState === 'awaiting_cnh') {
  const hasCnh = incoming === '1' || /^sim/.test(incoming)
  result = { response: `✅\n\nQual o *estado* onde você mora? (UF)`, newState: 'awaiting_residence_state', ctx: { ...ctx, hasCnh } }
}
if (!result && currentState === 'awaiting_residence_state') {
  const uf = incoming.toUpperCase().trim()
  if (!VALID_UF.includes(uf)) {
    result = { response: '❌ UF inválida (ex: SP, RJ):', newState: currentState, ctx }
  } else {
    result = { response: `${uf} ✅\n\nQual o *valor do veículo*? (ex: 60000)`, newState: 'awaiting_vehicle_value', ctx: { ...ctx, residenceState: uf } }
  }
}
if (!result && currentState === 'awaiting_vehicle_value') {
  const v = parseMoney(incoming)
  if (isNaN(v) || v <= 0) {
    result = { response: '❌ Valor inválido:', newState: currentState, ctx }
  } else {
    result = { response: `${fmt(v)} ✅\n\nVocê tem *entrada*?\n\n1️⃣ Sim\n2️⃣ Não`, newState: 'awaiting_vehicle_down_payment', ctx: { ...ctx, vehicleValue: v } }
  }
}
if (!result && currentState === 'awaiting_vehicle_down_payment') {
  if (incoming === '1' || /^sim/.test(incoming)) {
    result = { response: 'Qual o valor da *entrada*? (ex: 10000)', newState: 'awaiting_down_payment_amount', ctx }
  } else {
    result = { response: `Ok.\n\nEm quantos *meses* quer financiar?\n\n1️⃣ 12 meses\n2️⃣ 24 meses\n3️⃣ 36 meses\n4️⃣ 48 meses\n5️⃣ 60 meses\n\nOu informe diretamente (6 a 420):`, newState: 'awaiting_term', ctx: { ...ctx, downPaymentAmount: 0 } }
  }
}

// ── Pessoal/Consignado/Empresa/Equipamento/Rural ───────────────
if (!result && currentState === 'awaiting_loan_amount') {
  const v = parseMoney(incoming)
  if (isNaN(v) || v <= 0) {
    result = { response: '❌ Valor inválido. Informe o valor desejado:', newState: currentState, ctx }
  } else {
    const ft = ctx.financingType
    if (ft === 'empresa' || ft === 'equipamento') {
      result = { response: `${fmt(v)} ✅\n\nQual a *finalidade* do crédito? (ex: capital de giro, aquisição de equipamento)`, newState: 'awaiting_loan_purpose', ctx: { ...ctx, loanAmount: v } }
    } else {
      result = { response: `${fmt(v)} ✅\n\nQual seu *vínculo empregatício*?\n\n1️⃣ CLT\n2️⃣ Servidor Público\n3️⃣ Autônomo\n4️⃣ Empresário\n5️⃣ Aposentado/Pensionista`, newState: 'awaiting_employment_type', ctx: { ...ctx, loanAmount: v } }
    }
  }
}
if (!result && currentState === 'awaiting_loan_purpose') {
  result = { response: `Registrado ✅\n\nQual seu *vínculo empregatício*?\n\n1️⃣ CLT\n2️⃣ Servidor Público\n3️⃣ Autônomo\n4️⃣ Empresário\n5️⃣ Aposentado/Pensionista`, newState: 'awaiting_employment_type', ctx: { ...ctx, loanPurpose: rawText.trim() } }
}
if (!result && currentState === 'awaiting_employment_type') {
  const et = EMPLOY_MAP[incoming]
  if (!et) {
    result = { response: '❌ Escolha de 1 a 5:', newState: currentState, ctx }
  } else {
    result = { response: `${et} ✅\n\nQual o nome do seu *empregador* / empresa?`, newState: 'awaiting_employer', ctx: { ...ctx, employmentType: et } }
  }
}
if (!result && currentState === 'awaiting_employer') {
  result = { response: `Registrado ✅\n\nEm quantos *meses* quer o crédito?\n\n1️⃣ 12 meses\n2️⃣ 24 meses\n3️⃣ 36 meses\n4️⃣ 48 meses\n5️⃣ 60 meses\n\nOu informe diretamente (6 a 420):`, newState: 'awaiting_term', ctx: { ...ctx, employer: rawText.trim() } }
}

// ── Prazo ─────────────────────────────────────────────────────
if (!result && currentState === 'awaiting_term') {
  let term = TERM_SHORTCUTS[incoming] ?? null
  if (!term) { const n = parseInt(incoming); if (!isNaN(n) && n>=6 && n<=420) term = n }
  if (!term) {
    result = { response: '❌ Prazo inválido. Informe meses entre 6 e 420:', newState: currentState, ctx }
  } else {
    const requestedAmount = ctx.propertyValue ?? ctx.vehicleValue ?? ctx.loanAmount ?? 0
    const downPayment     = ctx.downPaymentAmount ?? 0
    const fgts            = ctx.fgtsAmount ?? 0
    result = {
      response: `⏳ Calculando para *${ctx.name ?? ctx.companyName ?? 'você'}*...\n\nConsultando taxas dos principais bancos.`,
      newState: 'simulation_ready',
      ctx: { ...ctx, termMonths: term, requestedAmount, downPaymentAmount: downPayment, fgtsAmount: fgts },
      triggerSimulation: true,
      simulationPayload: {
        whatsappNumber:      phone,
        financingType:       ctx.financingType,
        requestedAmount,
        downPaymentAmount:   downPayment,
        fgtsAmount:          fgts,
        termMonths:          term,
        realEstateObjective: ctx.realEstateObjective,
        purchaseTimeline:    ctx.purchaseTimeline,
        includeFees:         ctx.includeFees,
        propertyValue:       ctx.propertyValue,
        propertyType:        ctx.propertyType,
        propertyCity:        ctx.propertyCity,
        propertyState:       ctx.propertyState,
        vehicleType:         ctx.vehicleType,
        vehicleBrand:        ctx.vehicleBrand,
        vehicleModel:        ctx.vehicleModel,
        vehicleYear:         ctx.vehicleYear,
        vehicleFuel:         ctx.vehicleFuel,
        sellerContext:       ctx.sellerContext,
        purchaseIntent:      ctx.purchaseIntent,
        hasCnh:              ctx.hasCnh,
        residenceState:      ctx.residenceState,
        employmentType:      ctx.employmentType,
        employer:            ctx.employer,
        loanPurpose:         ctx.loanPurpose,
      },
      clientPayload: {
        whatsappNumber:              phone,
        personType:                  ctx.personType,
        name:                        ctx.name,
        cpf:                         ctx.cpf,
        birthDate:                   ctx.birthDate,
        civilStatus:                 ctx.civilStatus,
        email:                       ctx.email,
        phone:                       ctx.phone,
        city:                        ctx.city,
        state:                       ctx.state,
        monthlyIncome:               ctx.monthlyIncome,
        hasCoParticipant:            ctx.hasCoParticipant,
        coParticipantIncome:         ctx.coParticipantIncome,
        companyName:                 ctx.companyName,
        cnpj:                        ctx.cnpj,
        responsibleName:             ctx.responsibleName,
        companyRevenue:              ctx.companyRevenue,
      },
    }
  }
}

// ── Pós-simulação ─────────────────────────────────────────────
if (!result && currentState === 'simulation_ready') {
  if (incoming === '1' || /^sim/.test(incoming)) {
    result = { response: '👨‍💼 Perfeito! Um consultor entrará em contato em breve.\n\nObrigado por escolher nossos serviços! 🏠', newState: 'human_handoff', ctx, triggerHandoff: true }
  } else if (incoming === '2' || /^n[ãa]o/.test(incoming)) {
    result = { response: '😊 Tudo bem! Qualquer dúvida é só enviar "oi".', newState: 'completed', ctx }
  }
}

// ── Fallback ──────────────────────────────────────────────────
if (!result) {
  result = {
    response: 'Desculpe, não entendi. Envie "oi" para recomeçar ou "cancelar" para sair.',
    newState: currentState, ctx,
  }
}

return [{ json: {
  phone,
  phoneNumberId,
  response:          result.response,
  newState:          result.newState,
  newContext:        result.ctx,
  triggerSimulation: result.triggerSimulation ?? false,
  simulationPayload: result.simulationPayload ?? null,
  clientPayload:     result.clientPayload     ?? null,
  triggerHandoff:    result.triggerHandoff    ?? false,
} }]

